const PROCESSING_FEE = 5;

const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string };
type Step = { items: Item[] };
type Scenario = { steps: Step[] };

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_BASE_PREMIUM = 60;

export function processScenario(scenario: unknown): unknown {
  const { steps } = scenario as Scenario;
  const items = steps[0].items;
  const componentCountsByType = new Map<string, number>();
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCountsByType.set(
        item.type,
        (componentCountsByType.get(item.type) ?? 0) + 1,
      );
    }
  }
  const hasBlock = Array.from(componentCountsByType.values()).some(
    (count) => count === 3,
  );
  const basePremium = hasBlock
    ? BLOCK_BASE_PREMIUM
    : items.reduce(
        (sum, item) => sum + (BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0),
        0,
      );
  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
}

