import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote - base premium calculation", () => {
    it("should return premium 5 G for empty item list (just processing fee)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 5 }] });
    });
    it("should return premium 105 G for a single sword (100 base + 5 fee)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "sword" }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 105 }] });
    });
    it("should return premium 65 G for a single amulet (60 base + 5 fee)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "amulet" }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 65 }] });
    });
    it("should return premium 85 G for a single staff (80 base + 5 fee)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "staff" }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 85 }] });
    });
    it("should return premium 45 G for a single potion (40 base + 5 fee)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "potion" }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 45 }] });
    });
    it("should return premium 30 G for a single rune component (25 base + 5 fee)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "rune" }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 30 }] });
    });
    it("should return premium 30 G for a single moonstone component (25 base + 5 fee)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "moonstone" }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 30 }] });
    });
    it("should sum base premiums of multiple distinct items (sword + amulet = 160 + 5 fee = 165 G)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "sword" }, { type: "amulet" }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 165 }] });
    });
  });

  describe("quote - component blocks", () => {
    it("should charge 65 G for 3 alike runes (60 block base + 5 fee)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 65 }] });
    });
    it("should charge 65 G for 3 alike moonstones (60 block base + 5 fee)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 65 }] });
    });
    it("should charge 80 G for 2 runes + 1 moonstone — no block applies (75 base + 5 fee)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 80 }] });
    });
    it("should charge 105 G for 4 runes — block requires exactly 3 alike (100 base + 5 fee)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 105 }] });
    });
    it("should charge 125 G for 3 runes + 3 moonstones — two separate blocks (120 base + 5 fee)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 125 }] });
    });
  });

  describe("quote - item-specific modifiers", () => {
    it("should apply +50% curse surcharge to a cursed sword (100 + 50 = 150 base + 5 fee = 155 G)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 155 }] });
    });
    it("should apply +30% high-enchantment surcharge to a sword with enchantment >= 5 (100 + 30 = 130 base + 5 fee = 135 G)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 135 }] });
    });
    it("should not apply high-enchantment surcharge below threshold (enchantment 4 sword = 105 G)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 105 }] });
    });
    it("should apply +10% first-insurance surcharge to each item in a quote (sword = 110 base + 5 fee = 115 G)", () => {
      const scenario = { customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "sword" }] }] };
      expect(processScenario(scenario)).toEqual({ results: [{ premium: 115 }] });
    });
    it.todo("should stack curse and high-enchantment surcharges on the same item (cursed sword ench 7 = 100 + 50 + 30 = 180 base + 5 fee = 185 G)");
  });

  describe("quote - policy-wide modifiers", () => {
    it.todo("should apply -20% loyalty discount when yearsWithMHPCO >= 2 (sword for 2-year customer = 100 * 0.8 + 10 first ins = 90 base + 5 fee = 95 G)");
    it.todo("should not apply loyalty discount when yearsWithMHPCO < 2 (sword for 1-year customer = 100 + 10 first ins = 110 base + 5 fee = 115 G)");
    it.todo("should apply -15% follow-up discount when customer is on 2nd+ contract (sword = 100 * 0.85 + 10 first ins = 95 base + 5 fee = 100 G)");
  });

  describe("quote - integration examples from spec", () => {
    it.todo("should compute 165 G for newcomer (0 years, 1st contract) with cursed steel sword enchantment 3");
    it.todo("should compute 160 G for 3-year customer on 2nd contract with cursed steel sword enchantment 7");
  });

  describe("quote - rounding", () => {
    it.todo("should round final premium UP to whole G in MHPCO's favor");
  });

  describe("quote - validation", () => {
    it.todo("should reject quote with unknown item type (non-zero exit, error to stderr)");
  });

  describe("claim - base payout calculation", () => {
    it.todo("should pay out damage minus 100 G deductible for a standard item (sword damaged 500 G -> 400 G)");
    it.todo("should pay out 0 G when damage equals deductible (sword damaged 100 G -> 0 G)");
    it.todo("should pay out damage minus deductible for a component (rune damaged 200 G -> 100 G)");
  });

  describe("claim - special reimbursement rules", () => {
    it.todo("should reimburse 50% of damage then subtract deductible for highly enchanted item (sword ench 8 damaged 1000 G -> 500 - 100 = 400 G)");
    it.todo("should fully reimburse dragon-material item then subtract deductible (dragon sword damaged 1000 G -> 1000 - 100 = 900 G)");
    it.todo("should apply 50% rule (not dragon rule) when both apply (dragon sword ench 8 damaged 1000 G -> 500 - 100 = 400 G)");
  });

  describe("claim - rounding", () => {
    it.todo("should round final payout DOWN to whole G");
  });

  describe("claim - validation", () => {
    it.todo("should reject claim that references an item not in the policy (non-zero exit, error to stderr)");
    it.todo("should reject claim with negative damage amount (non-zero exit, error to stderr)");
    it.todo("should reject the whole claim when damages of a type exceed insured quantity (non-zero exit, error to stderr)");
  });

  describe("scenario processing", () => {
    it.todo("should return empty results for a scenario with no steps");
    it.todo("should process quote and claim steps sequentially and preserve order in results");
    it.todo("should allow a claim step to reference a prior quote step by index");
  });
});

