1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string; cursed?: boolean; enchantment?: number };
13	type Damage = { itemType: string; amount: number };
14	type Incident = { cause: string; damages: Damage[] };
15	type Step = { op?: string; items?: Item[]; policy?: number; incident?: Incident };
16	type Customer = { yearsWithMHPCO: number };
17	type Scenario = { customer: Customer; steps: Step[] };
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_BASE_PREMIUM = 60;
21	
22	function computeQuotePremium(
23	  items: Item[],
24	  customer: Customer,
25	  quoteIndex: number,
26	): number {
27	  const componentCountsByType = new Map<string, number>();
28	  let itemAdjustedSum = 0;
29	  let policyBasePremium = 0;
30	  for (const item of items) {
31	    if (!(item.type in BASE_PREMIUM_BY_ITEM_TYPE)) {
32	      throw new Error(`Unknown item type: ${item.type}`);
33	    }
34	    if (COMPONENT_TYPES.has(item.type)) {
35	      componentCountsByType.set(
36	        item.type,
37	        (componentCountsByType.get(item.type) ?? 0) + 1,
38	      );
39	    } else {
40	      const base = BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
41	      let itemPremium = base;
42	      if (item.cursed) {
43	        itemPremium += base * 0.5;
44	      }
45	      if (item.enchantment !== undefined && item.enchantment >= 5) {
46	        itemPremium += base * 0.3;
47	      }
48	      itemPremium += base * 0.1;
49	      itemAdjustedSum += itemPremium;
50	      policyBasePremium += base;
51	    }
52	  }
53	  for (const [type, count] of componentCountsByType) {
54	    if (count === 3) {
55	      itemAdjustedSum += BLOCK_BASE_PREMIUM + BLOCK_BASE_PREMIUM * 0.1;
56	      policyBasePremium += BLOCK_BASE_PREMIUM;
57	    } else {
58	      const componentBase = BASE_PREMIUM_BY_ITEM_TYPE[type] ?? 0;
59	      itemAdjustedSum += count * (componentBase + componentBase * 0.1);
60	      policyBasePremium += count * componentBase;
61	    }
62	  }
63	  let loyaltyDiscount = 0;
64	  if (customer.yearsWithMHPCO >= 2) {
65	    loyaltyDiscount = policyBasePremium * 0.2;
66	  }
67	  let followUpDiscount = 0;
68	  if (quoteIndex >= 1) {
69	    followUpDiscount = policyBasePremium * 0.15;
70	  }
71	  return Math.ceil(
72	    itemAdjustedSum - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
73	  );
74	}
75	
76	const DEDUCTIBLE = 100;
77	
78	function computeClaimPayout(incident: Incident, items: Item[]): number {
79	  const damageCountsByType = new Map<string, number>();
80	  for (const damage of incident.damages) {
81	    damageCountsByType.set(
82	      damage.itemType,
83	      (damageCountsByType.get(damage.itemType) ?? 0) + 1,
